import { createAuthPlugin } from "@better-auth-ui/core"
import {
  passkeyPlugin as corePasskeyPlugin,
  type PasskeyPluginOptions
} from "@better-auth-ui/core/plugins/passkey"

import { PasskeyButton } from "@/components/auth/passkey/passkey-button"
import { PasskeysSettings as Passkeys } from "@/components/auth/passkey/passkeys"

export const passkeyPlugin = createAuthPlugin(
  corePasskeyPlugin.id,
  (options: PasskeyPluginOptions = {}) => ({
    ...corePasskeyPlugin(options),
    authButtons: [PasskeyButton],
    securityCards: [Passkeys]
  })
)

import type { AuthPlugin } from "@better-auth-ui/core"
import {
  passkeyPlugin as corePasskeyPlugin,
  type PasskeyLocalization,
  passkeyLocalization
} from "@better-auth-ui/core/plugins/passkey"

export function passkeyLabels(auth: { plugins: AuthPlugin[] }) {
  const plugin = auth.plugins.find(
    (plugin) => plugin.id === corePasskeyPlugin.id
  )

  return {
    ...passkeyLocalization,
    ...(plugin?.localization as Partial<PasskeyLocalization> | undefined)
  }
}

import { type AuthView, authMutationKeys } from "@better-auth-ui/core"
import type { PasskeyAuthClient } from "@better-auth-ui/core/plugins/passkey"
import { useAuth } from "@better-auth-ui/solid"
import { useSignInPasskey } from "@better-auth-ui/solid/plugins/passkey"
import { useIsMutating } from "@tanstack/solid-query"
import { Fingerprint } from "lucide-solid"
import { passkeyLabels } from "@/components/auth/passkey/passkey-localization"
import { Button } from "@/components/ui/button"
import { Spinner } from "@/components/ui/spinner"
import { cn } from "@/lib/utils"

export type PasskeyButtonProps = {
  view?: AuthView
}

export function PasskeyButton(props: PasskeyButtonProps) {
  const auth = useAuth<PasskeyAuthClient>()
  const labels = () => passkeyLabels(auth)
  const signInPasskey = useSignInPasskey(auth.authClient, {
    onSuccess: () => auth.navigate({ to: auth.redirectTo })
  })
  const signInMutating = useIsMutating(() => ({
    mutationKey: authMutationKeys.signIn.all
  }))
  const signUpMutating = useIsMutating(() => ({
    mutationKey: authMutationKeys.signUp.all
  }))
  const isPending = () =>
    signInPasskey.isPending || signInMutating() + signUpMutating() > 0

  if (props.view === "signUp") return null

  return (
    <Button
      class={cn("w-full", isPending() && "pointer-events-none opacity-50")}
      disabled={isPending()}
      onClick={() => signInPasskey.mutate(undefined as never)}
      type="button"
      variant="outline"
    >
      {isPending() ? <Spinner /> : <Fingerprint />}
      {auth.localization.auth.continueWith.replace(
        "{{provider}}",
        labels().passkey
      )}
    </Button>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { Fingerprint, X } from "lucide-solid"
import { createSignal } from "solid-js"
import { DeletePasskeyDialog } from "@/components/auth/passkey/delete-passkey-dialog"
import { passkeyLabels } from "@/components/auth/passkey/passkey-localization"
import type { ListedPasskey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"

export function Passkey(props: { passkey: ListedPasskey }) {
  const auth = useAuth()
  const labels = () => passkeyLabels(auth)
  const [deleteOpen, setDeleteOpen] = createSignal(false)
  const passkeyName = () => props.passkey.name || labels().passkey

  return (
    <div class="flex items-center gap-3 p-4 text-sm">
      <div class="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
        <Fingerprint class="size-4.5" />
      </div>

      <div class="flex min-w-0 flex-col">
        <span class="truncate font-medium leading-tight">{passkeyName()}</span>
        <span class="text-muted-foreground text-xs">
          {new Date(props.passkey.createdAt).toLocaleString(undefined, {
            dateStyle: "medium",
            timeStyle: "short"
          })}
        </span>
      </div>

      <Dialog open={deleteOpen()} onOpenChange={setDeleteOpen}>
        <DialogTrigger
          as={Button}
          aria-label={labels().deletePasskey.replace("{{name}}", passkeyName())}
          class="ml-auto shrink-0"
          size="sm"
          variant="outline"
        >
          <X />
          {auth.localization.settings.delete}
        </DialogTrigger>
        <DeletePasskeyDialog
          onOpenChange={setDeleteOpen}
          passkey={props.passkey}
        />
      </Dialog>
    </div>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { Fingerprint } from "lucide-solid"
import { passkeyLabels } from "@/components/auth/passkey/passkey-localization"
import { Button } from "@/components/ui/button"

export function PasskeysEmpty(props: { onAddPress: () => void }) {
  const auth = useAuth()
  const labels = () => passkeyLabels(auth)

  return (
    <div class="flex flex-col items-center justify-center gap-4 p-6 text-center">
      <div class="flex size-10 items-center justify-center rounded-md bg-muted">
        <Fingerprint class="size-4.5" />
      </div>

      <div class="flex flex-col items-center justify-center gap-1">
        <p class="font-semibold text-sm">{labels().noPasskeys}</p>
        <p class="text-muted-foreground text-xs">
          {labels().passkeysDescription}
        </p>
      </div>

      <Button onClick={props.onAddPress} size="sm" type="button">
        {labels().addPasskey}
      </Button>
    </div>
